import React from 'react';
import { Metadata } from 'next';
import Breadcrumb from '@/components/breadcrumb/breadcrumb';
import { schoolData } from '@/data/schoolData';
import ImagePlaceholder from '@/components/ui/placeholder';
import styles from './facilities.module.scss';
import Link from 'next/link';

export const metadata: Metadata = {
  title: "Premium Facilities - Sree Jayam School",
};

export default function FacilitiesPage() {
  const { facilities } = schoolData;
  
  // Custom icons for the infrastructure grid
  const infraIcons: Record<string, string> = {
    "Laboratories": "🔬",
    "Computer Lab": "💻",
    "Library": "📚",
    "Sports Facilities": "⚽"
  };

  const infraDetails = [
    { title: "Laboratories", desc: "Physics, Chemistry, Biology, Computer, Math, Composite, Robotics" },
    { title: "Computer Lab", desc: "State-of-the-art Hardware & Software ecosystems" },
    { title: "Library", desc: "Extensively stocked physical and digital archives" },
    { title: "Sports Facilities", desc: "Table Tennis, Shuttle, Cricket, Basketball, Football & Athletics" }
  ];

  return (
    <main className={styles.modernFacilities}>
      <Breadcrumb title="Our Facilities" subtitle="Home" sub_title="Facilities" />
      
      {/* Hero Section */}
      <section className={`${styles.heroSection} pt-120 pb-80`}>
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-lg-10 text-center">
              <span className={styles.badge}>Campus Highlights</span>
              <h2 className={styles.modernTitle}>Designed for <span className="text-highlight">Excellence</span></h2>
              <p className={styles.modernSubtitle}>
                We believe that a conducive environment is paramount to a student's development. Our campus integrates nature with state-of-the-art architecture.
              </p>
            </div>
          </div>
        </div>
      </section>

      {/* Modern Bento Grid */}
      <section className={`${styles.bentoGrid} pb-100`}>
        <div className="container">
          <div className="row g-4">
            {facilities.map((fac, index) => {
              // Creating a dynamic bento layout where some cards are wider
              const isLarge = index === 0 || index === facilities.length - 1;
              const colClass = isLarge ? "col-lg-8 col-md-12" : "col-lg-4 col-md-6";
              
              return (
                <div key={index} className={colClass}>
                  <div className={styles.bentoCard}>
                    <div className={styles.bentoImageWrapper}>
                        <ImagePlaceholder text={fac.title} height={isLarge ? "400px" : "400px"} />
                    </div>
                    <div className={styles.bentoOverlay}>
                        <div className={styles.bentoContent}>
                           <h3>{fac.title}</h3>
                           <p>{fac.description}</p>
                           <span className={styles.exploreBtn}>Explore</span>
                        </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </section>
      
      {/* Infrastructure Floating Cards Instead of Table */}
      <section className={`${styles.infraSection} pt-100 pb-120`}>
        <div className="container">
            <div className="row justify-content-center mb-60">
                <div className="col-lg-8 text-center">
                   <h2 className={styles.modernTitle}>Core <span className="text-highlight">Infrastructure</span></h2>
                </div>
            </div>
            
            <div className="row g-4">
                {infraDetails.map((item, i) => (
                    <div className="col-lg-6 mb-4" key={i}>
                        <div className={styles.infraCard}>
                            <div className={styles.infraIcon}>
                               {infraIcons[item.title]}
                            </div>
                            <div className={styles.infraText}>
                                <h4>{item.title}</h4>
                                <p>{item.desc}</p>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
            
            <div className="row justify-content-center mt-50">
               <div className="col-auto">
                 <Link href="/gallery" className="tp-btn">View Full Gallery</Link>
               </div>
            </div>
        </div>
      </section>
    </main>
  );
}
